def test_manager_create_employee_missing_mandatory_field_email(http_client, manager_session, employee_db):
    headers = {"Authorization": f"Bearer {manager_session['token']}"}
    payload = {"first_name": "Jane", "last_name": "Smith", "department_id": 2}
    resp = http_client.post("http://target/employees", json=payload, headers=headers)
    assert resp.status_code == 400
    assert "email" in resp.json()["error"].lower()
    count_before = employee_db.count_documents({"first_name": "Jane"})
    assert count_before == 0

def test_non_manager_role_forbidden_to_create_employee(http_client, employee_session, employee_db):
    headers = {"Authorization": f"Bearer {employee_session['token']}"}
    payload = {"first_name": "Alice", "last_name": "Brown", "email": "alice@example.com", "department_id": 1}
    resp = http_client.post("http://target/employees", json=payload, headers=headers)
    assert resp.status_code == 403
    assert "permission" in resp.json()["error"].lower() or "insufficient" in resp.json()["error"].lower()
    count = employee_db.count_documents({"first_name": "Alice"})
    assert count == 0

def test_manager_create_employee_email_field_boundary_max_length(http_client, manager_session):
    long_email = 'a' * 243 + '@example.com'
    assert len(long_email) == 254
    headers = {"Authorization": f"Bearer {manager_session['token']}"}
    payload = {"first_name": "Max", "last_name": "Email", "email": long_email, "department_id": 1}
    resp = http_client.post("http://target/employees", json=payload, headers=headers)
    assert resp.status_code == 201
    assert resp.json()["email"] == long_email

def test_manager_create_employee_email_field_exceeds_max_length(http_client, manager_session, employee_db):
    long_email = 'a' * 244 + '@example.com'
    assert len(long_email) == 255
    headers = {"Authorization": f"Bearer {manager_session['token']}"}
    payload = {"first_name": "Over", "last_name": "Limit", "email": long_email, "department_id": 1}
    resp = http_client.post("http://target/employees", json=payload, headers=headers)
    assert resp.status_code == 400
    count = employee_db.count_documents({"first_name": "Over"})
    assert count == 0

